98:  async createWorktree(name: string, baseBranch: string, basePath: string, skipCopyIgnored?: boolean, purpose: 'agent' | 'manual' = 'manual'): Promise<string> {
99:    const wtPath = path.join(this.cwd, basePath, name)
100:    ensureDirSync(wtPath)
101:
102:    // Get current branch before creating worktree
103:    const currentBranch = await this.getCurrentBranch()
104:
105:    // Try to fetch, but don't fail if we can't (e.g., in devcontainer without credentials)
106:    try {
107:      await this.git.fetch()
108:    } catch {
109:      console.warn('⚠️  Could not fetch from remote (this is normal in devcontainers or offline mode)')
110:    }
111:
112:    await this.git.raw(['worktree', 'add', '-B', name, wtPath, baseBranch])
113:
114:    // Save worktree metadata
115:    const metadataService = new WorktreeMetadataService()
116:    await metadataService.save(wtPath, {
117:      sourceBranch: currentBranch,
118:      createdAt: new Date().toISOString(),
119:      createdFrom: this.cwd,
120:      baseBranch,
121:      purpose,
122:    })
123:
124:    // Copy ignored files if configured and not skipped
125:    if (!skipCopyIgnored) {
126:      try {
127:        const config = await loadConfig()
128:        if (config.worktree?.copyIgnoredFiles?.length) {
129:          console.log('\n📁 Copying ignored files to worktree...')
130:          await copyIgnoredFiles({
131:            sourceRoot: this.cwd,
132:            worktreeRoot: wtPath,
133:            config,
134:          })
135:        }
136:      } catch (error) {
137:        console.warn('⚠️  Failed to copy ignored files:', error instanceof Error ? error.message : error)
138:        // Don't fail worktree creation if copying fails
139:      }
140:    }
141:
142:    // Run maproom scan to index the new worktree
143:    await this.runMaproomScan(wtPath)
144:
145:    return wtPath
146:  }
