4:export interface WorktreeMetadata {
5:  sourceBranch: string
6:  createdAt: string
7:  createdFrom: string
8:  baseBranch: string
9:  purpose: 'agent' | 'manual'
10:}
11:
12:export class WorktreeMetadataService {
13:  private metadataFileName = '.crewchief-meta.json'
14:
15:  async save(worktreePath: string, metadata: WorktreeMetadata): Promise<void> {
16:    const metadataPath = path.join(worktreePath, this.metadataFileName)
17:    await fs.writeFile(metadataPath, JSON.stringify(metadata, null, 2))
18:  }
19:
20:  async read(worktreePath: string): Promise<WorktreeMetadata | null> {
21:    try {
22:      const metadataPath = path.join(worktreePath, this.metadataFileName)
23:      const content = await fs.readFile(metadataPath, 'utf-8')
24:      return JSON.parse(content) as WorktreeMetadata
25:    } catch {
26:      return null
27:    }
28:  }
29:
30:  async delete(worktreePath: string): Promise<void> {
31:    try {
32:      const metadataPath = path.join(worktreePath, this.metadataFileName)
33:      await fs.unlink(metadataPath)
34:    } catch {
35:      // Ignore errors if file doesn't exist
36:    }
37:  }
38:}
